1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Scenario = { steps: Array<{ op: string; items: Array<Item> }> };
3	
4	const PROCESSING_FEE = 5;
5	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
6	const CURSED_SURCHARGE_RATE = 0.5;
7	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
8	const HIGH_ENCHANTMENT_THRESHOLD = 5;
9	
10	const BASE_PREMIUMS: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	function withFirstInsuranceSurcharge(basePremium: number): number {
20	  return basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
21	}
22	
23	function surchargeIf(condition: boolean, basePremium: number, rate: number): number {
24	  return condition ? basePremium * rate : 0;
25	}
26	
27	function quoteItem(item: Item): number {
28	  const basePremium = BASE_PREMIUMS[item.type];
29	  const isHighlyEnchanted = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
30	  const cursedSurcharge = surchargeIf(item.cursed === true, basePremium, CURSED_SURCHARGE_RATE);
31	  const highEnchantmentSurcharge = surchargeIf(
32	    isHighlyEnchanted,
33	    basePremium,
34	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
35	  );
36	  return withFirstInsuranceSurcharge(basePremium) + cursedSurcharge + highEnchantmentSurcharge;
37	}
38	
39	const COMPONENT_TYPES = ["rune", "moonstone"];
40	const BLOCK_OF_THREE_BASE = 60;
41	
42	function countByType(items: Array<Item>): Record<string, number> {
43	  const counts: Record<string, number> = {};
44	  for (const item of items) {
45	    counts[item.type] = (counts[item.type] ?? 0) + 1;
46	  }
47	  return counts;
48	}
49	
50	export function processScenario(scenario: unknown): { results: Array<{ premium?: number }> } {
51	  const { steps } = scenario as Scenario;
52	  const items = steps[0].items;
53	  const counts = countByType(items);
54	
55	  let itemsPremium = 0;
56	  const bundledTypes = new Set<string>();
57	  for (const componentType of COMPONENT_TYPES) {
58	    if (counts[componentType] === 3) {
59	      itemsPremium += withFirstInsuranceSurcharge(BLOCK_OF_THREE_BASE);
60	      bundledTypes.add(componentType);
61	    }
62	  }
63	
64	  for (const item of items) {
65	    if (bundledTypes.has(item.type)) continue;
66	    itemsPremium += quoteItem(item);
67	  }
68	
69	  const premium = Math.ceil(itemsPremium + PROCESSING_FEE);
70	  return { results: [{ premium }] };
71	}
